// 7-Segment Counter with 2 Buttons (0-9)
// Button UP (D9): increment counter
// Button DOWN (D10): decrement counter
// Range: 0-9 (clamps at limits)

const int segA = 2;
const int segB = 3;
const int segC = 4;
const int segD = 5;
const int segE = 6;
const int segF = 7;
const int segG = 8;

const int btnUp = 9;
const int btnDown = 10;

int counter = 0;
int lastBtnUpState = HIGH;
int lastBtnDownState = HIGH;

void setup() {
  pinMode(segA, OUTPUT);
  pinMode(segB, OUTPUT);
  pinMode(segC, OUTPUT);
  pinMode(segD, OUTPUT);
  pinMode(segE, OUTPUT);
  pinMode(segF, OUTPUT);
  pinMode(segG, OUTPUT);

  pinMode(btnUp, INPUT_PULLUP);
  pinMode(btnDown, INPUT_PULLUP);

  displayDigit(counter);
}

void loop() {
  int btnUpState = digitalRead(btnUp);
  int btnDownState = digitalRead(btnDown);

  // Detect LOW→HIGH transition (button release)
  if (btnUpState == HIGH && lastBtnUpState == LOW) {
    if (counter < 9) {
      counter++;
    }
    displayDigit(counter);
    delay(20);
  }

  if (btnDownState == HIGH && lastBtnDownState == LOW) {
    if (counter > 0) {
      counter--;
    }
    displayDigit(counter);
    delay(20);
  }

  lastBtnUpState = btnUpState;
  lastBtnDownState = btnDownState;
}

void displayDigit(int n) {
  // Turn off all segments first
  digitalWrite(segA, LOW);
  digitalWrite(segB, LOW);
  digitalWrite(segC, LOW);
  digitalWrite(segD, LOW);
  digitalWrite(segE, LOW);
  digitalWrite(segF, LOW);
  digitalWrite(segG, LOW);

  // Display digit 0-9
  if (n == 0) {
    digitalWrite(segA, HIGH);
    digitalWrite(segB, HIGH);
    digitalWrite(segC, HIGH);
    digitalWrite(segD, HIGH);
    digitalWrite(segE, HIGH);
    digitalWrite(segF, HIGH);
  } else if (n == 1) {
    digitalWrite(segB, HIGH);
    digitalWrite(segC, HIGH);
  } else if (n == 2) {
    digitalWrite(segA, HIGH);
    digitalWrite(segB, HIGH);
    digitalWrite(segD, HIGH);
    digitalWrite(segE, HIGH);
    digitalWrite(segG, HIGH);
  } else if (n == 3) {
    digitalWrite(segA, HIGH);
    digitalWrite(segB, HIGH);
    digitalWrite(segC, HIGH);
    digitalWrite(segD, HIGH);
    digitalWrite(segG, HIGH);
  } else if (n == 4) {
    digitalWrite(segB, HIGH);
    digitalWrite(segC, HIGH);
    digitalWrite(segF, HIGH);
    digitalWrite(segG, HIGH);
  } else if (n == 5) {
    digitalWrite(segA, HIGH);
    digitalWrite(segC, HIGH);
    digitalWrite(segD, HIGH);
    digitalWrite(segF, HIGH);
    digitalWrite(segG, HIGH);
  } else if (n == 6) {
    digitalWrite(segA, HIGH);
    digitalWrite(segC, HIGH);
    digitalWrite(segD, HIGH);
    digitalWrite(segE, HIGH);
    digitalWrite(segF, HIGH);
    digitalWrite(segG, HIGH);
  } else if (n == 7) {
    digitalWrite(segA, HIGH);
    digitalWrite(segB, HIGH);
    digitalWrite(segC, HIGH);
  } else if (n == 8) {
    digitalWrite(segA, HIGH);
    digitalWrite(segB, HIGH);
    digitalWrite(segC, HIGH);
    digitalWrite(segD, HIGH);
    digitalWrite(segE, HIGH);
    digitalWrite(segF, HIGH);
    digitalWrite(segG, HIGH);
  } else if (n == 9) {
    digitalWrite(segA, HIGH);
    digitalWrite(segB, HIGH);
    digitalWrite(segC, HIGH);
    digitalWrite(segD, HIGH);
    digitalWrite(segF, HIGH);
    digitalWrite(segG, HIGH);
  }
}

